vokabeln = {"Hund": "dog", "Katze": "cat", "Haus": "house"}

wort = input("Deutsches Wort: ")
print(vokabeln.get(wort, "unbekannt"))

punkte = 0

for deutsch, englisch in vokabeln.items():
    antwort = input(f"{deutsch}? ")
    if antwort == englisch:
        print("Richtig!")
        punkte += 1
    else:
        print(f"Falsch: {englisch}")

print(f"Punkte: {punkte}/{len(vokabeln)}")

class Trainer:
    def __init__(self, vokabeln):
        self.vokabeln = vokabeln
        self.punkte = 0

    def pruefen(self, wort, antwort):
        if self.vokabeln.get(wort) == antwort:
            self.punkte += 1
            return "Richtig!"
        return f"Falsch: {self.vokabeln.get(wort, 'unbekannt')}"

trainer = Trainer({"Hund": "dog"})
print(trainer.pruefen("Hund", "dog"))   # Richtig!
print(trainer.punkte)                     # 1

